170→    fun handleEditPostResult(data: Intent?) {
171→        val localPostId = data?.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0)
172→        if (localPostId == null || localPostId == 0) {
173→            return
174→        }
175→        val post = postStore.getPostByLocalPostId(localPostId)
176→        if (post != null) {
177→            triggerPostUploadAction(EditPostResult(site, post, data) { publishPost(localPostId) })
178→        }
179→    }
180→
181→    fun handleRemotePreview(localPostId: Int, remotePreviewType: RemotePreviewType) {
182→        val post = postStore.getPostByLocalPostId(localPostId)
183→        if (post != null) {
184→            triggerPostListAction.invoke(PostListAction.RemotePreviewPost(site, post, remotePreviewType))
185→        }
186→    }
187→
188→    fun publishPost(localPostId: Int) {
189→        val post = postStore.getPostByLocalPostId(localPostId)
190→        if (post != null) {
191→            triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
192→        }
193→    }
194→
195→    fun publishPost(post: PostModel) {
196→        triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
197→    }
198→
199→    fun resolveConflictsAndEditPost(localPostId: Int) {
200→        val post = postStore.getPostByLocalPostId(localPostId)
201→        if (post != null) {
202→            performChecksAndEdit(site, post)
203→        }
204→    }
205→
206→    fun moveTrashedPostToDraft(localPostId: Int) {
207→        val post = postStore.getPostByLocalPostId(localPostId)
208→        if (post != null) {
209→            moveTrashedPostToDraft(post)
210→        }
211→    }
