 70→    // Assumes all lines after first line will not be indented
 71→    public static void indentTextViewFirstLine(TextView textView, int textOffsetX) {
 72→        if (textView == null || textOffsetX < 0) {
 73→            return;
 74→        }
 75→
 76→        SpannableString text = new SpannableString(textView.getText());
 77→        text.setSpan(new TextWrappingLeadingMarginSpan(textOffsetX), 0, text.length(),
 78→                     Spanned.SPAN_EXCLUSIVE_EXCLUSIVE);
 79→        textView.setText(text);
 80→    }
