308→        private void getNoteFromBundleIfExists() {
309→            if (mIntent.hasExtra(ARG_NOTE_BUNDLE)) {
310→                Bundle payload = mIntent.getBundleExtra(ARG_NOTE_BUNDLE);
311→                mNote = NotificationsUtils.buildNoteObjectFromBundle(payload);
312→            }
313→        }
