540→        // Like or unlike a comment via the REST API
541→        private void likeComment() {
542→            if (mNote == null) {
543→                requestFailed(ARG_ACTION_LIKE);
544→                return;
545→            }
546→
547→            SiteModel site = mSiteStore.getSiteBySiteId(mNote.getSiteId());
548→
549→            // Bump analytics
550→            // TODO klymyam remove legacy comment tracking after new comments are shipped and new funnels are made
551→            AnalyticsUtils.trackWithBlogPostDetails(
552→                    AnalyticsTracker.Stat.NOTIFICATION_QUICK_ACTIONS_LIKED, mNote.getSiteId(), mNote.getPostId());
553→            AnalyticsUtils.trackCommentActionWithSiteDetails(Stat.COMMENT_QUICK_ACTION_LIKED,
554→                    AnalyticsCommentActionSource.NOTIFICATIONS, site);
555→            AnalyticsUtils.trackQuickActionTouched(
556→                    QuickActionTrackPropertyValue.LIKE,
557→                    site,
558→                    mNote.buildComment());
559→
560→            if (site != null) {
561→                mCommentsStoreAdapter.dispatch(CommentActionBuilder.newLikeCommentAction(
562→                        new RemoteLikeCommentPayload(site, mNote.getCommentId(), true)));
563→            } else {
564→                requestFailed(ARG_ACTION_LIKE);
565→                AppLog.e(T.NOTIFS, "Site with id: " + mNote.getSiteId() + " doesn't exist in the Site store");
566→            }
567→        }
568→
569→        private void approveComment() {
570→            if (mNote == null) {
571→                requestFailed(ARG_ACTION_APPROVE);
572→                return;
573→            }
574→
575→            SiteModel site = mSiteStore.getSiteBySiteId(mNote.getSiteId());
576→
577→            // Bump analytics
578→            // TODO klymyam remove legacy comment tracking after new comments are shipped and new funnels are made
579→            AnalyticsUtils.trackWithBlogPostDetails(
580→                    AnalyticsTracker.Stat.NOTIFICATION_QUICK_ACTIONS_APPROVED, mNote.getSiteId(), mNote.getPostId());
581→            AnalyticsUtils.trackCommentActionWithSiteDetails(Stat.COMMENT_QUICK_ACTION_APPROVED,
582→                    AnalyticsCommentActionSource.NOTIFICATIONS, site);
583→
584→            AnalyticsUtils.trackQuickActionTouched(
585→                    QuickActionTrackPropertyValue.APPROVE,
586→                    site,
587→                    mNote.buildComment());
588→
589→            // Update pseudo comment (built from the note)
590→            CommentModel comment = mNote.buildComment();
591→            comment.setStatus(CommentStatus.APPROVED.toString());
592→
593→            if (site == null) {
594→                AppLog.e(T.NOTIFS, "Impossible to approve a comment on a site that is not in the App. SiteId: "
595→                                   + mNote.getSiteId());
596→                requestFailed(ARG_ACTION_APPROVE);
597→                return;
598→            }
599→
600→            // keep the CommentId, we'll use it later to know whether to trigger the end processing notification
601→            // or not
602→            keepRemoteCommentIdForPostProcessing(comment.getRemoteCommentId());
603→
604→            // Push the comment
605→            mCommentsStoreAdapter.dispatch(CommentActionBuilder
606→                    .newPushCommentAction(new RemoteCommentPayload(site, comment)));
607→        }
608→
609→        private void replyToComment() {
610→            if (mNote == null) {
611→                requestFailed(ARG_ACTION_APPROVE);
612→                return;
613→            }
614→
615→            if (TextUtils.isEmpty(mReplyText)) return;
616→
617→            SiteModel site = mSiteStore.getSiteBySiteId(mNote.getSiteId());
618→            if (site == null) {
619→                AppLog.e(T.NOTIFS, "Impossible to reply to a comment on a site that is not in the App."
620→                                   + " SiteId: " + mNote.getSiteId());
621→                requestFailed(ARG_ACTION_APPROVE);
622→                return;
623→            }
624→
625→            // Pseudo comment (built from the note)
626→            CommentModel comment = mNote.buildComment();
627→
628→            // Pseudo comment reply
629→            CommentModel reply = new CommentModel();
630→            reply.setContent(mReplyText);
631→
632→            // Push the reply
633→            RemoteCreateCommentPayload payload = new RemoteCreateCommentPayload(site, comment, reply);
634→            mCommentsStoreAdapter.dispatch(CommentActionBuilder.newCreateNewCommentAction(payload));
635→
636→            // Bump analytics
637→            AnalyticsUtils.trackCommentReplyWithDetails(
638→                    true,
639→                    site,
640→                    comment,
641→                    AnalyticsCommentActionSource.NOTIFICATIONS
642→            );
643→            AnalyticsUtils.trackQuickActionTouched(QuickActionTrackPropertyValue.REPLY_TO, site, comment);
644→        }
