651→    // OnChanged events
652→
653→    @SuppressWarnings("unused")
654→    @Subscribe(threadMode = ThreadMode.MAIN)
655→    public void onCommentChanged(OnCommentChanged event) {
656→        if (mQuickActionProcessor == null) {
657→            return;
658→        }
659→
660→        // LIKE_COMMENT events do not hold event.changedCommentsLocalIds info so, just process them
661→        // also CREATE_NEW_COMMENT, which are received for REPLY quick actions won't have a matching id as FluxC
662→        // only notifies us of _new_ comments (the actual reply) so, no way to connect one another in this place.
663→        // Therefore, we only care and match for `PUSH_COMMENT` to make sure there's a corresponding initial APPROVE
664→        // quick action that corresponds to the resulting FluxC event.
665→        if (event.causeOfChange == CommentAction.PUSH_COMMENT) {
666→            List<Long> eventChangedCommentsRemoteIds = new ArrayList<>();
667→            if (mActionedCommentsRemoteIds.size() > 0) {
668→                // prepare a comparable list of Ids
669→                for (Integer commentLocalId : event.changedCommentsLocalIds) {
670→                    CommentModel localComment = mCommentsStoreAdapter.getCommentByLocalId(commentLocalId);
671→                    if (localComment != null) {
672→                        eventChangedCommentsRemoteIds.add(localComment.getRemoteCommentId());
673→                    }
674→                }
675→
676→                // here we need to check ids: is an event corresponding to an action triggered from this Service?
677→                for (Long oneEventCommentRemoteId : eventChangedCommentsRemoteIds) {
678→                    if (mActionedCommentsRemoteIds.contains(oneEventCommentRemoteId)) {
679→                        if (event.isError()) {
680→                            mQuickActionProcessor.requestFailed(ARG_ACTION_APPROVE);
681→                        } else {
682→                            mQuickActionProcessor.requestCompleted(ARG_ACTION_APPROVE);
683→                        }
684→                    }
685→                }
686→            }
687→
688→            // now remove any remoteIds for already processed actions
689→            for (Long remoteId : eventChangedCommentsRemoteIds) {
690→                mActionedCommentsRemoteIds.remove(remoteId);
691→            }
692→        } else if (event.causeOfChange == CommentAction.LIKE_COMMENT) {
693→            if (event.isError()) {
694→                mQuickActionProcessor.requestFailed(ARG_ACTION_LIKE);
695→            } else {
696→                mQuickActionProcessor.requestCompleted(ARG_ACTION_LIKE);
697→            }
698→        } else if (event.causeOfChange == CommentAction.CREATE_NEW_COMMENT) {
699→            if (event.isError()) {
700→                mQuickActionProcessor.requestFailed(ARG_ACTION_REPLY);
701→            } else {
702→                mQuickActionProcessor.requestCompleted(ARG_ACTION_REPLY);
703→            }
704→        }
705→    }
706→}
