1267→    private static void browsePostOrPageEx(
1268→            Context context,
1269→            SiteModel site,
1270→            PostImmutableModel post,
1271→            RemotePreviewType remotePreviewType) {
1272→        if (site == null || post == null || TextUtils.isEmpty(post.getLink())) {
1273→            return;
1274→        }
1275→
1276→        if (remotePreviewType == RemotePreviewType.REMOTE_PREVIEW_WITH_REMOTE_AUTO_SAVE
1277→                        && TextUtils.isEmpty(post.getAutoSavePreviewUrl())) {
1278→            return;
1279→        }
1280→
1281→        String url = PostUtils.getPreviewUrlForPost(remotePreviewType, post);
1282→
1283→        String shareableUrl = post.getLink();
1284→        String shareSubject = post.getTitle();
1285→        boolean startPreviewForResult = remotePreviewType != RemotePreviewType.NOT_A_REMOTE_PREVIEW;
1286→
1287→        if (site.isWPCom()) {
1288→            WPWebViewActivity.openPostUrlByUsingGlobalWPCOMCredentials(
1289→                    context,
1290→                    url,
1291→                    shareableUrl,
1292→                    shareSubject,
1293→                    true,
1294→                    startPreviewForResult);
1295→        } else if (site.isWPComAtomic() && !site.isPrivateWPComAtomic()) {
1296→            openAtomicBlogPostPreview(
1297→                    context,
1298→                    url,
1299→                    site.getLoginUrl(),
1300→                    site.getFrameNonce());
1301→        } else if (site.isJetpackConnected() && site.isUsingWpComRestApi()) {
1302→            WPWebViewActivity
1303→                    .openJetpackBlogPostPreview(
1304→                            context,
1305→                            url,
1306→                            shareableUrl,
1307→                            shareSubject,
1308→                            site.getFrameNonce(),
1309→                            true,
1310→                            startPreviewForResult,
1311→                            site.isPrivateWPComAtomic() ? site.getSiteId() : 0);
1312→        } else {
1313→            // Add the original post URL to the list of allowed URLs.
1314→            // This is necessary because links are disabled in the webview, but WP removes "?preview=true"
1315→            // from the passed URL, and internally redirects to it. EX:Published posts on a site with Plain
1316→            // permalink structure settings.
1317→            // Ref: https://github.com/wordpress-mobile/WordPress-Android/issues/4873
1318→            WPWebViewActivity.openUrlByUsingBlogCredentials(
1319→                    context,
1320→                    site,
1321→                    post,
1322→                    url,
1323→                    new String[]{post.getLink()},
1324→                    true,
1325→                    true,
1326→                    startPreviewForResult);
1327→        }
1328→    }
