1330→    private static void openAtomicBlogPostPreview(Context context, String url, String authenticationUrl,
1331→                                                 String frameNonce) {
1332→        try {
1333→            Intent intent = new Intent(Intent.ACTION_VIEW);
1334→            intent.setData(Uri.parse(authenticationUrl + "?redirect_to=" + URLEncoder
1335→                    .encode(url + "&frame-nonce=" + UrlUtils.urlEncode(frameNonce), ENCODING_UTF8)));
1336→            context.startActivity(intent);
1337→        } catch (UnsupportedEncodingException e) {
1338→            e.printStackTrace();
1339→        }
1340→    }
