1700→     * open the passed url in the device's external browser
1701→     */
1702→    public static void openUrlExternal(Context context, @NonNull String url) {
1703→        Uri uri = Uri.parse(url);
1704→        Intent intent = new Intent(Intent.ACTION_VIEW, uri);
1705→        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
1706→
1707→        try {
1708→            // Disable deeplinking activity so to not catch WP URLs.
1709→            // We'll re-enable them later - see callers of WPActivityUtils#enableReaderDeeplinks.
1710→            WPActivityUtils.disableReaderDeeplinks(context);
1711→
1712→            context.startActivity(intent);
1713→        } catch (ActivityNotFoundException e) {
1714→            ToastUtils.showToast(context, context.getString(R.string.cant_open_url), ToastUtils.Duration.LONG);
1715→            AppLog.e(AppLog.T.UTILS, "No default app available on the device to open the link: " + url, e);
1716→        } catch (SecurityException se) {
1717→            AppLog.e(AppLog.T.UTILS, "Error opening url in default browser. Url: " + url, se);
1718→
1719→            List<ResolveInfo> infos = context.getPackageManager().queryIntentActivities(intent, 0);
1720→            if (infos.size() == 1) {
1721→                // there's only one handler and apparently it caused the exception so, just inform and bail
1722→                AppLog.d(AppLog.T.UTILS, "Only one url handler found so, bailing.");
1723→                ToastUtils.showToast(context, context.getString(R.string.cant_open_url));
1724→            } else {
1725→                Intent chooser = Intent.createChooser(intent, context.getString(R.string.error_please_choose_browser));
1726→                context.startActivity(chooser);
1727→            }
1728→        }
1729→    }
