 75→    /*
 76→     * collapses shortcodes in the passed post content, stripping anything between the
 77→     * shortcode name and the closing brace
 78→     * ex: collapseShortcodes("[gallery ids="1206,1205,1191"]") -> "[gallery]"
 79→     */
 80→    public static String collapseShortcodes(final String postContent) {
 81→        // speed things up by skipping regex if content doesn't contain a brace
 82→        if (postContent == null || !postContent.contains("[")) {
 83→            return postContent;
 84→        }
 85→
 86→        String shortCode;
 87→        Pattern p = Pattern.compile("(\\[ *([^ ]+) [^\\[\\]]*\\])");
 88→        Matcher m = p.matcher(postContent);
 89→        StringBuffer sb = new StringBuffer();
 90→        while (m.find()) {
 91→            shortCode = m.group(2);
 92→            if (isKnownShortcode(shortCode)) {
 93→                m.appendReplacement(sb, "[" + shortCode + "]");
 94→            } else {
 95→                AppLog.d(AppLog.T.POSTS, "unknown shortcode - " + shortCode);
 96→            }
 97→        }
 98→        m.appendTail(sb);
 99→
100→        return sb.toString();

