 15→
 16→public class CommentUtils {
 17→    /*
 18→     * displays comment text as html, including retrieving images
 19→     */
 20→    public static void displayHtmlComment(TextView textView, String content, int maxImageSize, int maxEmojiSize,
 21→                                          String errorParseMsg) {
 22→        if (textView == null) {
 23→            return;
 24→        }
 25→
 26→        if (content == null) {
 27→            textView.setText(null);
 28→            return;
 29→        }
 30→
 31→        // skip performance hit of html conversion if content doesn't contain html
 32→        if (!content.contains("<") && !content.contains("&")) {
 33→            content = content.trim();
 34→            textView.setText(content);
 35→            // make sure unnamed links are clickable
 36→            if (content.contains("://")) {
 37→                Linkify.addLinks(textView, Linkify.WEB_URLS);
 38→            }
 39→            return;
 40→        }
 41→
 42→        // convert emoticons first (otherwise they'll be downloaded)
 43→        content = EmoticonsUtils.replaceEmoticonsWithEmoji(content);
 44→
 45→        // now convert to HTML with an image getter that enforces a max image size
 46→        final Spanned html;
 47→        if (maxImageSize > 0 && content.contains("<img")) {
 48→            html = HtmlUtils.fromHtml(content, new WPCustomImageGetter(textView, maxImageSize, maxEmojiSize));
 49→        } else {
 50→            html = HtmlUtils.fromHtml(content);
 51→        }
 52→
 53→        // remove extra \n\n added by Html.convert()
 54→        int start = 0;
 55→        int end = html.length();
 56→        while (start < end && Character.isWhitespace(html.charAt(start))) {
 57→            start++;
 58→        }
 59→        while (end > start && Character.isWhitespace(html.charAt(end - 1))) {
 60→            end--;
 61→        }
 62→
 63→        if (html.length() == 0) {
 64→            textView.setText(errorParseMsg);
 65→        } else {
 66→            textView.setText(html.subSequence(start, end));
 67→        }
 68→    }
