 74→        }
 75→
 76→        SpannableString text = new SpannableString(textView.getText());
 77→        text.setSpan(new TextWrappingLeadingMarginSpan(textOffsetX), 0, text.length(),
 78→                     Spanned.SPAN_EXCLUSIVE_EXCLUSIVE);
