183→    private class QuickActionProcessor {
184→        private SystemNotificationsTracker mSystemNotificationsTracker;
185→        private GCMMessageHandler mGCMMessageHandler;
186→        private String mNoteId;
187→        private String mReplyText;
188→        private String mActionType;
189→        private NotificationType mNotificationType;
190→        private int mPushId;
191→        private Note mNote;
192→        private final int mTaskId;
193→        private final Context mContext;
194→        private final Intent mIntent;
195→
196→        QuickActionProcessor(Context ctx, SystemNotificationsTracker notificationsTracker,
197→                             GCMMessageHandler gcmMessageHandler, Intent intent, int taskId) {
198→            mContext = ctx;
199→            mSystemNotificationsTracker = notificationsTracker;
200→            mIntent = intent;
201→            mTaskId = taskId;
202→            this.mGCMMessageHandler = gcmMessageHandler;
203→        }
204→
205→        public void process() {
206→            getDataFromIntent();
207→
208→            // now handle each action
209→            if (mActionType != null) {
210→                // check special cases for authorization push
211→                if (mActionType.equals(ARG_ACTION_AUTH_IGNORE)) {
212→                    // dismiss notifs
213→                    NativeNotificationsUtils.dismissNotification(
214→                            NotificationPushIds.ACTIONS_RESULT_NOTIFICATION_ID, mContext);
215→                    NativeNotificationsUtils.dismissNotification(
216→                            NotificationPushIds.AUTH_PUSH_NOTIFICATION_ID, mContext);
217→                    NativeNotificationsUtils.dismissNotification(
218→                            NotificationPushIds.ACTIONS_PROGRESS_NOTIFICATION_ID, mContext);
219→                    mGCMMessageHandler.removeNotification(NotificationPushIds.AUTH_PUSH_NOTIFICATION_ID);
220→
221→                    AnalyticsTracker.track(AnalyticsTracker.Stat.PUSH_AUTHENTICATION_IGNORED);
222→                    return;
223→                }
224→
225→                // check notification dismissed pending intent
226→                if (mActionType.equals(ARG_ACTION_NOTIFICATION_DISMISS)) {
227→                    if (mNotificationType != null) {
228→                        mSystemNotificationsTracker.trackDismissedNotification(mNotificationType);
229→                    }
230→                    int notificationId = mIntent.getIntExtra(ARG_PUSH_ID, 0);
231→                    if (notificationId == GROUP_NOTIFICATION_ID) {
232→                        mGCMMessageHandler.clearNotifications();
233→                    } else if (notificationId == QUICK_START_REMINDER_NOTIFICATION_ID) {
234→                        mQuickStartTracker.track(Stat.QUICK_START_NOTIFICATION_DISMISSED);
235→                    } else {
236→                        mGCMMessageHandler.removeNotification(notificationId);
237→                        // Dismiss the grouped notification if a user dismisses all notifications from a wear device
238→                        if (!mGCMMessageHandler.hasNotifications()) {
239→                            NotificationManagerCompat notificationManager = NotificationManagerCompat.from(mContext);
240→                            notificationManager.cancel(GROUP_NOTIFICATION_ID);
241→                        }
242→                    }
243→                    return;
244→                }
245→
246→                // check special cases for pending draft notifications - ignore
247→                if (mActionType.equals(ARG_ACTION_DRAFT_PENDING_IGNORE)) {
248→                    // dismiss notif
249→                    int postId = mIntent.getIntExtra(NotificationsPendingDraftsReceiver.POST_ID_EXTRA, 0);
250→                    if (postId != 0) {
251→                        NativeNotificationsUtils.dismissNotification(
252→                                PendingDraftsNotificationsUtils.makePendingDraftNotificationId(postId),
253→                                mContext
254→                        );
255→                    }
256→                    AnalyticsTracker.track(AnalyticsTracker.Stat.NOTIFICATION_PENDING_DRAFTS_IGNORED);
257→                    return;
258→                }
259→
260→                // check special cases for pending draft notifications - dismiss
261→                if (mActionType.equals(ARG_ACTION_DRAFT_PENDING_DISMISS)) {
262→                    AnalyticsTracker.track(AnalyticsTracker.Stat.NOTIFICATION_PENDING_DRAFTS_DISMISSED);
263→                    return;
264→                }
265→
266→                if (mActionType.equals(ARG_ACTION_REPLY)) {
267→                    // we don't need showing the infinite progress bar in case of REPLY on Android N,
268→                    // because we've got inline-reply there with its own spinner to show progress
269→                    // no op
270→                } else {
271→                    NativeNotificationsUtils
272→                            .showIntermediateMessageToUser(getProcessingTitleForAction(mActionType), mContext,
273→                                    mNotificationType);
274→                }
275→
276→                // if we still don't have a Note, go get it from the REST API
277→                if (mNote == null) {
278→                    RestRequest.Listener listener =
279→                            new RestRequest.Listener() {
280→                                @Override
281→                                public void onResponse(JSONObject response) {
282→                                    if (response != null && !response.optBoolean("success")) {
283→                                        // build the Note object here
284→                                        buildNoteFromJSONObject(response);
285→                                        performRequestedAction();
286→                                    }
287→                                }
288→                            };
289→
290→                    RestRequest.ErrorListener errorListener =
291→                            new RestRequest.ErrorListener() {
292→                                @Override
293→                                public void onErrorResponse(VolleyError error) {
294→                                    requestFailed(mActionType);
295→                                }
296→                            };
297→
298→                    getNoteFromNoteId(mNoteId, listener, errorListener);
299→                } else {
300→                    // we have a Note! just go ahead and perform the requested action
301→                    performRequestedAction();
302→                }
303→            } else {
304→                requestFailed(null);
305→            }
306→        }
