315→        private void getDataFromIntent() {
316→            if (mIntent == null) {
317→                return;
318→            }
319→            // get all needed data from intent
320→            mNoteId = mIntent.getStringExtra(ARG_NOTE_ID);
321→            mActionType = mIntent.getStringExtra(ARG_ACTION_TYPE);
322→            // default value for push notification ID is likely GROUP_NOTIFICATION_ID for the only
323→            // notif in active notifs map (there is only one notif if quick actions are available)
324→            mPushId = GROUP_NOTIFICATION_ID;
325→            if (mIntent.hasExtra(ARG_ACTION_REPLY_TEXT)) {
326→                mReplyText = mIntent.getStringExtra(ARG_ACTION_REPLY_TEXT);
327→            }
328→            if (mIntent.hasExtra(ARG_NOTIFICATION_TYPE)) {
329→                mNotificationType = (NotificationType) mIntent.getSerializableExtra(ARG_NOTIFICATION_TYPE);
330→            }
331→
332→            if (TextUtils.isEmpty(mReplyText)) {
333→                // if voice reply is enabled in a wearable, it will come through the remoteInput
334→                // extra EXTRA_VOICE_OR_INLINE_REPLY
335→                // same thing with direct-reply in Android 7
336→                Bundle remoteInput = RemoteInput.getResultsFromIntent(mIntent);
337→                if (remoteInput != null) {
338→                    obtainReplyTextFromRemoteInputBundle(remoteInput);
339→                }
340→            }
341→
342→            // we probably have the note in the PN payload and such it's passed in the intent extras
343→            // bundle. If we have it, no need to go fetch it through REST API.
344→            getNoteFromBundleIfExists();
345→        }
