418→        /*
419→         * called when action has been completed successfully
420→         */
421→        private void requestCompleted(String actionType) {
422→            String successMessage = null;
423→            if (actionType != null) {
424→                if (actionType.equals(ARG_ACTION_LIKE)) {
425→                    successMessage = getString(R.string.comment_liked);
426→                } else if (actionType.equals(ARG_ACTION_APPROVE)) {
427→                    successMessage = getString(R.string.comment_moderated_approved);
428→                } else if (actionType.equals(ARG_ACTION_REPLY)) {
429→                    successMessage = getString(R.string.note_reply_successful);
430→                }
431→            } else {
432→                // show generic success message here
433→                successMessage = getString(R.string.comment_q_action_done_generic);
434→            }
435→
436→            NotificationsActions.markNoteAsRead(mNote);
437→
438→            // dismiss any other pending result notification
439→            NativeNotificationsUtils.dismissNotification(
440→                    NotificationPushIds.ACTIONS_RESULT_NOTIFICATION_ID, mContext);
441→            // update notification indicating the operation succeeded
442→            NativeNotificationsUtils.showFinalMessageToUser(successMessage,
443→                    NotificationPushIds.ACTIONS_PROGRESS_NOTIFICATION_ID,
444→                    mContext,
445→                    NotificationType.ACTIONS_PROGRESS);
446→            // remove the original notification from the system bar
447→            mGCMMessageHandler.removeNotificationWithNoteIdFromSystemBar(mContext, mNoteId);
448→
449→            // after 3 seconds, dismiss the notification that indicated success
450→            Handler handler = new Handler(getMainLooper());
451→            handler.postDelayed(new Runnable() {
452→                public void run() {
453→                    NativeNotificationsUtils.dismissNotification(
454→                            NotificationPushIds.ACTIONS_PROGRESS_NOTIFICATION_ID, mContext);
455→                }
456→            }, 3000); // show the success message for 3 seconds, then dismiss
457→
458→            stopSelf(mTaskId);
459→        }
