 458→    /**
 459→     * Opens the editor and passes the information needed for a reblog action
 460→     *
 461→     * @param activity the calling activity
 462→     * @param site     the site on which the post should be reblogged
 463→     * @param post     the post to be reblogged
 464→     */
 465→    public static void openEditorForReblog(
 466→            Activity activity,
 467→            @Nullable SiteModel site,
 468→            @Nullable ReaderPost post,
 469→            PagePostCreationSourcesDetail reblogSource
 470→    ) {
 471→        if (post == null) {
 472→            ToastUtils.showToast(activity, R.string.post_not_found, ToastUtils.Duration.SHORT);
 473→            return;
 474→        }
 475→
 476→        if (site == null) {
 477→            ToastUtils.showToast(activity, R.string.blog_not_found, ToastUtils.Duration.SHORT);
 478→            return;
 479→        }
 480→
 481→        AnalyticsUtils.trackWithReblogDetails(
 482→            reblogSource == PagePostCreationSourcesDetail.POST_FROM_REBLOG
 483→                    ? READER_ARTICLE_REBLOGGED
 484→                    : READER_ARTICLE_DETAIL_REBLOGGED,
 485→            post.blogId,
 486→            post.postId,
 487→            site.getSiteId()
 488→        );
 489→
 490→        Intent editorIntent = new Intent(activity, EditPostActivity.class);
 491→        editorIntent.putExtra(EditPostActivity.EXTRA_REBLOG_POST_TITLE, post.getTitle());
 492→        editorIntent.putExtra(EditPostActivity.EXTRA_REBLOG_POST_QUOTE, post.getExcerpt());
 493→        editorIntent.putExtra(EditPostActivity.EXTRA_REBLOG_POST_IMAGE, post.getFeaturedImage());
 494→        editorIntent.putExtra(EditPostActivity.EXTRA_REBLOG_POST_CITATION, post.getUrl());
 495→        editorIntent.setAction(EditPostActivity.ACTION_REBLOG);
 496→
 497→        addNewPostForResult(editorIntent, activity, site, false, reblogSource, -1, null);
 498→    }
