 947→    public static void viewCurrentSite(Context context, SiteModel site, boolean openFromHeader) {
 948→        AnalyticsTracker.Stat stat = openFromHeader ? AnalyticsTracker.Stat.OPENED_VIEW_SITE_FROM_HEADER
 949→                : AnalyticsTracker.Stat.OPENED_VIEW_SITE;
 950→        AnalyticsUtils.trackWithSiteDetails(stat, site);
 951→
 952→        if (site == null) {
 953→            ToastUtils.showToast(context, R.string.blog_not_found, ToastUtils.Duration.SHORT);
 954→        } else if (site.getUrl() == null) {
 955→            ToastUtils.showToast(context, R.string.blog_not_found, ToastUtils.Duration.SHORT);
