 957→        } else {
 958→            String siteUrl = site.getUrl();
 959→            if (site.isWPCom()) {
 960→                // Show wp.com sites authenticated
 961→                WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(context, siteUrl, true);
 962→            } else if (!TextUtils.isEmpty(site.getUsername()) && !TextUtils.isEmpty(site.getPassword())) {
 963→                // Show self-hosted sites as authenticated since we should have the username & password
 964→                WPWebViewActivity
 965→                        .openUrlByUsingBlogCredentials(context, site, null, siteUrl, new String[]{}, false, true,
 966→                                false);
 967→            } else {
 968→                // Show non-wp.com sites without a password unauthenticated. These would be Jetpack sites that are
 969→                // connected through REST API.
 970→                WPWebViewActivity.openURL(context, siteUrl, true, site.isPrivateWPComAtomic() ? site.getSiteId() : 0);
 971→            }
 972→        }
