1731→    public static void openStatsUrl(Context context, @NonNull String url) {
1732→        if (url.startsWith("https://wordpress.com/my-stats") || url.startsWith("http://wordpress.com/my-stats")) {
1733→            // make sure to load the no-chrome version of Stats over https
1734→            url = UrlUtils.makeHttps(url);
1735→            if (url.contains("?")) {
1736→                // add the no chrome parameters if not available
1737→                if (!url.contains("?no-chrome") && !url.contains("&no-chrome")) {
1738→                    url += "&no-chrome";
1739→                }
1740→            } else {
1741→                url += "?no-chrome";
1742→            }
1743→            WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(context, url);
1744→        } else if (url.startsWith("https") || url.startsWith("http")) {
1745→            WPWebViewActivity.openURL(context, url);
1746→        }
1747→    }
